     1в†’/* в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
     2в†’   Jake OS вЂ” FГЎbrica de Criativos v2
     3в†’в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */
     4в†’(function () {
     5в†’  'use strict';
     6в†’
     7в†’  // в”Ђв”Ђ Estado в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
     8в†’  var _tipo        = 'imagem';   // 'imagem' | 'video'
     9в†’  var _modo        = 'anuncios'; // modo do especialista
    10в†’  var _modelo      = 'flux-1.1-pro';
    11в†’  var _promptExp   = '';
    12в†’  var _resultadoUrl= '';
    13в†’  var _uploadUrl   = '';         // URL Replicate da imagem uploadada (para I2V)
    14в†’  var _uploadB64   = '';         // base64 da imagem (para anГЎlise)
    15в†’  var _uploadMime  = 'image/jpeg';
    16в†’  var _usarI2V     = false;
    17в†’  var _predId      = '';         // prediction_id do vГ­deo em andamento
    18в†’  var _pollTimer   = null;
    19в†’  var _histPage    = 1;
    20в†’  var _histFiltros = { folder_id: '', tipo: '' };
    21в†’
    22в†’  // в”Ђв”Ђ DefiniГ§ГЈo de modelos в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    23в†’  var _MODELOS_IMAGEM = [
    24в†’    { key:'flux-1.1-pro',    nome:'Flux 1.1 Pro',       vel:'fast', custo:2 },
    25в†’    { key:'flux-dev',        nome:'Flux Dev',            vel:'med',  custo:2 },
    26в†’    { key:'recraft-v3',      nome:'Recraft V3',          vel:'fast', custo:2 },
    27в†’    { key:'ideogram-v3-turbo',nome:'Ideogram V3 Turbo', vel:'fast', custo:1 },
    28в†’    { key:'imagen-4',        nome:'Imagen 4',            vel:'med',  custo:3 },
    29в†’  ];
    30в†’  var _MODELOS_VIDEO = [
    31в†’    { key:'wan-t2v-fast',  nome:'Wan T2V Fast',     tipo:'T2V', vel:'fast', custo:1 },
    32в†’    { key:'wan-5b-fast',   nome:'Wan 5B Fast',      tipo:'T2V', vel:'med',  custo:2 },
    33в†’    { key:'hailuo-02',     nome:'Hailuo 02 Fast',   tipo:'T2V', vel:'fast', custo:2 },
    34в†’    { key:'seedance-lite', nome:'Seedance Lite',    tipo:'T2V', vel:'med',  custo:2 },
    35в†’    { key:'runway-gen4',   nome:'Runway Gen-4',     tipo:'T2V', vel:'fast', custo:3 },
    36в†’    { key:'wan-i2v-fast',  nome:'Wan I2V Fast',     tipo:'I2V', vel:'fast', custo:1 },
    37в†’  ];
    38в†’
    39в†’  // в”Ђв”Ђ Init в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    40в†’  function init() {
    41в†’    bindTipoToggle();
    42в†’    bindModos();
    43в†’    renderModelos();
    44в†’    bindUpload();
    45в†’    bindPromptActions();
    46в†’    bindGerarBtn();
    47в†’    bindResultadoAcoes();
    48в†’    bindAbas();
    49в†’    bindHistoricoEvents();
    50в†’    carregarPastas();
    51в†’    carregarHistorico();
    52в†’  }
    53в†’
    54в†’  // в”Ђв”Ђ Toggle Imagem / VГ­deo в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    55в†’  function bindTipoToggle() {
    56в†’    var btnImg = document.getElementById('cri-tipo-imagem');
    57в†’    var btnVid = document.getElementById('cri-tipo-video');
    58в†’    if (btnImg) btnImg.addEventListener('click', function () {
    59в†’      _tipo = 'imagem'; _modelo = 'flux-1.1-pro'; _usarI2V = false;
    60в†’      btnImg.classList.add('active'); btnVid.classList.remove('active');
    61в†’      renderModelos();
    62в†’      _setText('cri-modelos-label', 'Modelo de imagem');
    63в†’    });
    64в†’    if (btnVid) btnVid.addEventListener('click', function () {
    65в†’      _tipo = 'video'; _modelo = 'wan-t2v-fast';
    66в†’      btnVid.classList.add('active'); btnImg.classList.remove('active');
    67в†’      renderModelos();
    68в†’      _setText('cri-modelos-label', 'Modelo de vГ­deo');
    69в†’    });
    70в†’  }
    71в†’
    72в†’  // в”Ђв”Ђ Seletor de Modo в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    73в†’  function bindModos() {
    74в†’    document.querySelectorAll('.cri-modo-card').forEach(function (card) {
    75в†’      card.addEventListener('click', function () {
    76в†’        _modo = this.dataset.modo;
    77в†’        document.querySelectorAll('.cri-modo-card').forEach(function (c) { c.classList.remove('active'); });
    78в†’        this.classList.add('active');
    79в†’        esconder('cri-expandido-painel'); _promptExp = '';
    80в†’      });
    81в†’    });
    82в†’  }
    83в†’
    84в†’  // в”Ђв”Ђ Render modelos в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    85в†’  function renderModelos() {
    86в†’    var grid = document.getElementById('cri-modelos-grid');
    87в†’    if (!grid) return;
    88в†’    var lista = _tipo === 'imagem' ? _MODELOS_IMAGEM : _MODELOS_VIDEO;
    89в†’    grid.innerHTML = lista.map(function (m) {
    90в†’      var ativo = m.key === _modelo ? ' active' : '';
    91в†’      var disabled = (m.tipo === 'I2V' && !_usarI2V) ? ' disabled' : '';
    92в†’      var badges = '';
    93в†’      if (_tipo === 'imagem') {
    94в†’        badges = '<span class="cri-badge cri-badge-tipo-imagem">IMG</span>';
    95в†’      } else {
    96в†’        badges = '<span class="cri-badge cri-badge-tipo-' + (m.tipo === 'I2V' ? 'i2v' : 't2v') + '">' + m.tipo + '</span>';
    97в†’      }
    98в†’      badges += '<span class="cri-badge cri-badge-vel-' + m.vel + '">' + (m.vel === 'fast' ? 'вљЎ' : 'в—‘') + '</span>';
    99в†’      badges += '<span class="cri-badge cri-badge-custo-' + m.custo + '">' + '$'.repeat(m.custo) + '</span>';
   100в†’      return '<div class="cri-modelo-card' + ativo + disabled + '" data-key="' + m.key + '">' +
   101в†’        '<span class="cri-modelo-nome">' + _esc(m.nome) + '</span>' +
   102в†’        '<div class="cri-modelo-badges">' + badges + '</div></div>';
   103в†’    }).join('');
   104в†’    grid.querySelectorAll('.cri-modelo-card:not(.disabled)').forEach(function (card) {
   105в†’      card.addEventListener('click', function () {
   106в†’        _modelo = this.dataset.key;
   107в†’        grid.querySelectorAll('.cri-modelo-card').forEach(function (c) { c.classList.remove('active'); });
   108в†’        this.classList.add('active');
   109в†’      });
   110в†’    });
   111в†’  }
   112в†’
   113в†’  // в”Ђв”Ђ UtilitГЎrios в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
   114в†’  function _val(id) { var el = document.getElementById(id); return el ? el.value : ''; }
   115в†’  function _set(id, v) { var el = document.getElementById(id); if (el) el.value = v || ''; }
   116в†’  function _setText(id, t) { var el = document.getElementById(id); if (el) el.textContent = t || ''; }
   117в†’  function _esc(s) { return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
   118в†’  function mostrar(id) { var el = document.getElementById(id); if (el) el.classList.remove('hidden'); }
   119в†’  function esconder(id) { var el = document.getElementById(id); if (el) el.classList.add('hidden'); }
   120в†’
   121в†’  // в”Ђв”Ђ Observer para init lazy в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
   122в†’  var _iniciado = false;
   123в†’  var _obs = new MutationObserver(function (muts) {
   124в†’    muts.forEach(function (m) {
   125в†’      if (m.target.id === 'page-criativos' && m.target.classList.contains('active')) {
   126в†’        if (!_iniciado) { _iniciado = true; init(); }
   127в†’      }
   128в†’    });
   129в†’  });
   130в†’  var page = document.getElementById('page-criativos');
   131в†’  if (page) {
   132в†’    _obs.observe(page, { attributes: true, attributeFilter: ['class'] });
   133в†’    if (page.classList.contains('active')) { _iniciado = true; init(); }
   134в†’  }
   135в†’
   136в†’  // в”Ђв”Ђ Stubs para tasks seguintes в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
   137в†’  function bindUpload() {}
   138в†’  function bindPromptActions() {}
   139в†’  function bindGerarBtn() {}
   140в†’  function bindResultadoAcoes() {}
   141в†’  function bindAbas() {}
   142в†’  function bindHistoricoEvents() {}
   143в†’  function carregarPastas() {}
   144в†’  function carregarHistorico() {}
   145в†’
   146в†’})();
